from collections import defaultdict

class Solution(object):
    def treeQueries(self, n, edges, queries):
        adj = defaultdict(list)
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        # Euler tour: each node's subtree = contiguous range [tin, tout]
        tin = [0] * (n + 1)
        tout = [0] * (n + 1)
        parent = [0] * (n + 1)
        parent_weight = [0] * (n + 1)
        dist = [0] * (n + 1)  # initial dist from root 1
        timer = [0]
        order = []
        stack = [(1, 0, 0)]
        visited = [False] * (n + 1)
        visited[1] = True
        # Iterative DFS with post-order tracking
        stk = [(1, 0, 0, False)]
        while stk:
            u, p, w, post = stk.pop()
            if post:
                tout[u] = timer[0]
                continue
            timer[0] += 1
            tin[u] = timer[0]
            order.append(u)
            parent[u] = p
            parent_weight[u] = w
            if p:
                dist[u] = dist[p] + w
            stk.append((u, p, w, True))
            for v, wv in adj[u]:
                if v != p:
                    stk.append((v, u, wv, False))
        # Segment tree with lazy range-add, point-query
        lazy = [0] * (4 * (n + 1))
        def update(node, lo, hi, l, r, val):
            if r < lo or hi < l:
                return
            if l <= lo and hi <= r:
                lazy[node] += val
                return
            mid = (lo + hi) >> 1
            update(2*node, lo, mid, l, r, val)
            update(2*node+1, mid+1, hi, l, r, val)
        def query(node, lo, hi, pos):
            if lo == hi:
                return lazy[node]
            mid = (lo + hi) >> 1
            if pos <= mid:
                return lazy[node] + query(2*node, lo, mid, pos)
            return lazy[node] + query(2*node+1, mid+1, hi, pos)
        # Map edge to its child node
        edge_child = {}
        for u, v, w in edges:
            if parent[v] == u:
                edge_child[(u, v)] = v
                edge_child[(v, u)] = v
            else:
                edge_child[(u, v)] = u
                edge_child[(v, u)] = u
        cur_weight = {}
        for u, v, w in edges:
            child = edge_child[(u, v)]
            cur_weight[(min(u,v), max(u,v))] = w
        result = []
        for q in queries:
            if q[0] == 2:
                x = q[1]
                result.append(dist[x] + query(1, 1, n, tin[x]))
            else:
                _, u, v, new_w = q
                key = (min(u,v), max(u,v))
                child = edge_child[(u, v)]
                old_w = cur_weight[key]
                delta = new_w - old_w
                cur_weight[key] = new_w
                update(1, 1, n, tin[child], tout[child], delta)
        return result
